import java.io.*;

public class SafeDeserialiser {
    public static Object deserialise(byte[] data) throws Exception {
        ByteArrayInputStream bis = new ByteArrayInputStream(data);
        ObjectInputStream ois = new ObjectInputStream(bis);

        // Only allow UserProfile and basic Java types
        ois.setObjectInputFilter(filterInfo -> {
            Class<?> clazz = filterInfo.serialClass();
            if (clazz == null) return ObjectInputFilter.Status.UNDECIDED;
            if (clazz == UserProfile.class) return ObjectInputFilter.Status.ALLOWED;
            if (clazz == String.class) return ObjectInputFilter.Status.ALLOWED;
            if (clazz == Integer.class) return ObjectInputFilter.Status.ALLOWED;
            return ObjectInputFilter.Status.REJECTED;
        });

        return ois.readObject();
    }
}

