import pickle

class Temperature:
    def __init__(self, celsius):
        self.celsius = celsius
        self.fahrenheit = celsius * 9/5 + 32

    def __reduce__(self):
        # Tell pickle: to recreate me, call Temperature(celsius)
        return (Temperature, (self.celsius,))

    def __repr__(self):
        return f'{self.celsius}°C / {self.fahrenheit}°F'

