public class ByteTamperingDemo {
    public static void main(String[] args) throws Exception {
        // NORMAL: Serialise array [1, 2, 3, 4]
        int[] original = {1, 2, 3, 4};
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream oos = new ObjectOutputStream(baos);
        oos.writeObject(original);
        oos.close();
        byte[] data = baos.toByteArray();

        // ATTACK: Find and change value 3 → 99
        for (int i = 0; i < data.length - 3; i++) {
            // Look for 00 00 00 03 (integer 3)
            if (data[i]==0 && data[i+1]==0 && data[i+2]==0 && data[i+3]==3) {
                data[i+3] = 99; // Change 3 to 99!
                System.out.println("Tampered byte at offset " + i);
                break;
            }
        }

        // Deserialise tampered data
        ObjectInputStream ois = new ObjectInputStream(
            new ByteArrayInputStream(data));
        int[] tampered = (int[]) ois.readObject();
        System.out.println("Original: " + Arrays.toString(original));
        System.out.println("Tampered: " + Arrays.toString(tampered));
    }
}

