import java.io.*;

public class FilteredDeserialisation {
    public static void main(String[] args) throws Exception {
        // Serialise a legitimate GameState
        GameState game = new GameState("Alice", 5, 2500);
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream oos = new ObjectOutputStream(baos);
        oos.writeObject(game);
        oos.close();

        // Deserialise WITH filter
        ObjectInputStream ois = new ObjectInputStream(
            new ByteArrayInputStream(baos.toByteArray()));

        ois.setObjectInputFilter(info -> {
            Class<?> clazz = info.serialClass();
            if (clazz == null) return ObjectInputFilter.Status.UNDECIDED;
            // Only allow GameState and String
            if (clazz == GameState.class || clazz == String.class)
                return ObjectInputFilter.Status.ALLOWED;
            System.out.println("BLOCKED: " + clazz.getName());
            return ObjectInputFilter.Status.REJECTED;
        });

        GameState loaded = (GameState) ois.readObject();
        System.out.println("Safely loaded: " + loaded);
    }
}

import com.google.gson.Gson;
import com.google.gson.JsonSyntaxException;

public class JsonAlternative {
    public static void main(String[] args) {
        Gson gson = new Gson();

        // Serialise to JSON (safe!)
        GameState game = new GameState("Alice", 5, 2500);
        String json = gson.toJson(game);
        System.out.println("JSON: " + json);

        // Deserialise from JSON (safe!)
        GameState loaded = gson.fromJson(json, GameState.class);
        System.out.println("Loaded: " + loaded);

        // Even malicious JSON cannot execute code!
        String malicious = "{\"playerName\": \"admin\", \"level\": 999}";
        GameState parsed = gson.fromJson(malicious, GameState.class);
        System.out.println("From untrusted: " + parsed);
        // Still just data — no code execution possible!

        // But ALWAYS validate!
        if (parsed.level < 0 || parsed.level > 100) {
            System.out.println("REJECTED: level out of range!");
        }
    }
}

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.io.*;
import java.util.*;

public class HmacSerialisationDemo {
    static final String SECRET = "MySecretKey12345"; // In production: use env variable!

    static byte[] sign(byte[] data) throws Exception {
        Mac mac = Mac.getInstance("HmacSHA256");
        mac.init(new SecretKeySpec(SECRET.getBytes(), "HmacSHA256"));
        return mac.doFinal(data);
    }

    public static void main(String[] args) throws Exception {
        // Serialise
        int[] values = {1, 2, 3, 4};
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        ObjectOutputStream oos = new ObjectOutputStream(baos);
        oos.writeObject(values);
        oos.close();
        byte[] data = baos.toByteArray();
        byte[] signature = sign(data);

        System.out.println("Data: " + data.length + " bytes");
        System.out.println("HMAC: " + Base64.getEncoder().encodeToString(signature));

        // Verify BEFORE deserialising
        byte[] verify = sign(data);
        if (Arrays.equals(signature, verify)) {
            System.out.println("Signature VALID — safe to deserialise");
        }

        // Simulate tampering
        data[data.length - 1] ^= 0xFF; // Flip last byte
        byte[] badVerify = sign(data);
        if (!Arrays.equals(signature, badVerify)) {
            System.out.println("Signature INVALID — data was tampered!");
            System.out.println("REFUSING to deserialise!");
        }
    }
}

