import json

# LAYER 1: Prefer JSON over native serialisation
def receive_data(raw_bytes):
    try:
        data = json.loads(raw_bytes.decode('utf-8'))
    except (json.JSONDecodeError, UnicodeDecodeError) as e:
        raise ValueError(f'Invalid JSON: {e}')

    # LAYER 2: Validate data types
    if not isinstance(data, dict):
        raise ValueError('Expected JSON object')

    # LAYER 3: Validate required fields
    required = {'username': str, 'score': int, 'level': int}
    for field, expected_type in required.items():
        if field not in data:
            raise ValueError(f'Missing field: {field}')
        if not isinstance(data[field], expected_type):
            raise ValueError(f'{field} must be {expected_type.__name__}')

    # LAYER 4: Validate value ranges
    if not (1 <= len(data['username']) <= 50):
        raise ValueError('Username length out of range')
    if not (0 <= data['score'] <= 1000000):
        raise ValueError('Score out of range')
    if not (1 <= data['level'] <= 100):
        raise ValueError('Level out of range')

    # LAYER 5: Sanitise strings
    data['username'] = data['username'].strip()[:50]

    print(f'Validated: {data}')
    return data

